    make_q(15,"The range of y = x² is:",["All reals","*y ≥ 0","y ≤ 0","y > 0"],"Minimum at vertex (0,0)."),
    make_q(16,"The range of y = −x² + 4 is:",["y ≥ 4","*y ≤ 4","All reals","y ≥ 0"],"Maximum at vertex: y = 4."),
    make_q(17,"The domain of any quadratic function is:",["y ≥ 0","Only positive x","*All real numbers","x ≥ 0"],"Quadratics accept all x."),
    make_q(18,"A narrow parabola has |a| that is:",["Small","*Large (|a| > 1 = narrower)","Zero","Equal to 1"],"Larger |a| = steeper."),
    make_q(19,"A wide parabola has |a| that is:",["Large","*Small (0 < |a| < 1 = wider)","Equal to 1","Zero"],"Smaller |a| = flatter."),
