    make_q(15,"Residual analysis for quadratic regression: random residuals suggest:",["Bad fit","*Good fit","Linear model","Exponential model"],"Random = model captures the pattern."),
    make_q(16,"A quadratic model is sometimes called a _____ model.",["First-order","*Second-order (degree 2)","Third-order","Zero-order"],"Degree 2 polynomial."),
    make_q(17,"If data has a clear peak and then decreases, a _____ regression is appropriate.",["Linear","Exponential","*Quadratic (downward-opening parabola)","Logarithmic"],"Inverted U = quadratic."),
    make_q(18,"Projectile motion data (height vs. time) is best modeled by:",["Linear regression","*Quadratic regression","Exponential regression","No regression"],"Parabolic trajectory."),
