    make_q(14,"Factor: x⁴ − 16",["(x² + 4)(x + 2)","*(x² + 4)(x + 2)(x − 2)","(x − 2)⁴","Cannot factor"],"(x²)² − 4² = (x²+4)(x²−4) = (x²+4)(x+2)(x−2)."),
    make_q(15,"Solve x² − 36 = 0",["x = 36","x = 6 only","*x = 6 or x = −6","x = −36"],"(x+6)(x−6)=0."),
    make_q(16,"Factor: 50x² − 18",["(50x + 18)(x − 1)","*2(5x + 3)(5x − 3)","(5x + 3)(10x − 6)","Cannot factor"],"2(25x² − 9) = 2(5x+3)(5x−3)."),
    make_q(17,"Recognizing a difference of squares requires:",["Two perfect squares added","*Two perfect squares subtracted","Any two terms","Two negative terms"],"Must be subtraction of squares."),
    make_q(18,"Factor: (x + 3)² − 16",["Cannot factor","*(x + 7)(x − 1)","(x + 3 − 4)²","(x + 3)(x − 16)"],"Let u = x+3: u² − 4² = (u+4)(u−4) = (x+7)(x−1)."),
